// Record the outcome of an objectcache.test command. Stores the result JSON and
// the config hash that was tested. When the test passed, last_tested_at is set;
// the service passes NULL for a failed test to avoid advancing the timestamp.
// Runs under InTenantTx (operator path -- the operator triggered the test).
func (q *Queries) UpdateObjectCacheTestResult(ctx context.Context, arg UpdateObjectCacheTestResultParams) (UpdateObjectCacheTestResultRow, error) {
	row := q.db.QueryRow(ctx, updateObjectCacheTestResult,
		arg.LastTestConfigHash,
		arg.LastTestResultJson,
		arg.LastTestedAt,
		arg.SiteID,
		arg.TenantID,
	)
	var i UpdateObjectCacheTestResultRow
	err := row.Scan(
		&i.SiteID,
		&i.TenantID,
		&i.Enabled,
		&i.Scheme,
		&i.Host,
		&i.Port,
		&i.SocketPath,
		&i.Database,
		&i.Username,
		&i.Prefix,
		&i.MaxttlSeconds,
		&i.QueryttlSeconds,
		&i.ConnectTimeoutMs,
		&i.ReadTimeoutMs,
		&i.RetryCount,
		&i.RetryIntervalMs,
		&i.Serializer,
		&i.Compression,
		&i.AsyncFlush,
		&i.FlushStrategy,
		&i.Shared,
		&i.FlushOnFailback,
		&i.AnalyticsEnabled,
		&i.LastTestConfigHash,
		&i.LastTestResultJson,
		&i.LastTestedAt,
		&i.OcState,
		&i.OcLatencyMs,
		&i.OcLastErrorClass,
		&i.OcUsedMemoryBytes,
		&i.OcHitRatioPct,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

